test_cases.assertion_pseudocode:
customHTTP = &http.Client{Timeout: 5 * time.Second}
client = NewClient("https://api.example.com", WithHTTPClient(customHTTP))
assert client.httpClient == customHTTP

// Static analysis / compilation check
// Run: go build ./...
// Also: grep -rn 'type User struct' . | wc -l == 1
// Repeat for each canonical type name
assert compilationSucceeds()
assert typeDeclarationCount("User") == 1
assert typeDeclarationCount("APIKeyMeta") == 1
assert typeDeclarationCount("Organization") == 1
// etc. for all listed types

authReq = AuthCallbackRequest{Provider: "github", Code: "abc", RedirectURI: "http://localhost/cb"}
bytes = json.Marshal(authReq)
assert bytes does NOT contain '"expires"'

createOrgReq = CreateOrgRequest{Name: "Acme", Slug: "acme"}
bytes2 = json.Marshal(createOrgReq)
assert bytes2 does NOT contain '"url"'

updateOrgReq = UpdateOrgRequest{}
bytes3 = json.Marshal(updateOrgReq)
assert bytes3 does NOT contain '"name"'
assert bytes3 does NOT contain '"url"'

// Verified by compilation; signature checks
// The following MUST compile:
client.GetUser(ctx, WithIfNoneMatch("e"))
client.GetUserByID(ctx, "id", WithIfNoneMatch("e"))
client.GetToken(ctx, "tid", WithIfNoneMatch("e"))
client.GetOrg(ctx, "oid", WithIfNoneMatch("e"))

// The following MUST NOT compile (no RequestOption param):
// client.UpdateUser(ctx, req, WithIfNoneMatch("e")) -- compile error
// client.ListKeys(ctx, WithIfNoneMatch("e")) -- compile error
// Verify via go build ./...

apiErr = &APIError{Code: 404, Message: "User not found"}
assert apiErr.Error() == "API error 404: User not found"

apiErr2 = &APIError{Code: 500, Message: "Internal Server Error"}
assert apiErr2.Error() == "API error 500: Internal Server Error"

apiErr = &APIError{Code: 422, Message: "Validation failed"}
assert apiErr.Code == 422
assert apiErr.Message == "Validation failed"

// Compilation check via go build ./...
opts = &ListUsersOptions{IncludeBlocked: true}
assert opts.IncludeBlocked == true
// type assertion: ListUsers accepts *ListUsersOptions

// Compilation check via go build ./...
opts = &ListOrgsOptions{IncludeBlocked: true}
assert opts.IncludeBlocked == true
// type assertion: ListOrgs accepts *ListOrgsOptions

server = httptest.NewServer(func(w, r):
  if r.URL.Path == "/healthz":
    w.WriteHeader(200)
    w.Write(json({"status":"ok"}))
  else:
    http.Redirect(w, r, "/healthz", 302)
)
client = NewClient(server.URL)
// Trigger a redirecting endpoint indirectly by calling a health endpoint
// that the mock redirects
resp, err = client.Healthz(context.Background())
assert err == nil OR err contains redirect limit info

customHTTP = &http.Client{
  CheckRedirect: func(req *http.Request, via []*http.Request) error {
    return http.ErrUseLastResponse
  },
}
client = NewClient("https://example.com", WithHTTPClient(customHTTP))
assert client.httpClient == customHTTP
assert client.httpClient.CheckRedirect != nil

// Run: go build ./...
// Run: grep '^package' sdk.go sdk_types.go sdk_user.go sdk_admin.go sdk_auth.go sdk_health.go sdk_errors.go
// All lines must be 'package apikit'
assert all SDK files declare 'package apikit'
assert no SDK file is under internal/ directory

// Run: go build ./...
// Run: grep '^go ' go.mod
// go directive version must be >= 1.18
assert goVersion >= "1.18"
assert compilationSucceeds()
// Response[T] must be syntactically valid generic type

edge_case_tests.assertion_pseudocode:
// This is best tested via an internal/whitebox approach or by replacing
// the body encoder. Since all SDK types are valid JSON, this edge case
// is validated by ensuring the do method wraps marshal errors.
// Test with a mock that injects a marshal-failing body:
var requestMade bool
server = httptest.NewServer(func(w, r):
  requestMade = true
  w.WriteHeader(200)
)
// Simulate marshal failure via internal test hook or
// verify that fmt.Errorf("%w", marshalErr) is used in do
assert when marshal fails: err != nil
assert errors.Unwrap(err) != nil
assert requestMade == false
var apiErr *APIError
assert errors.As(err, &apiErr) == false

server = httptest.NewServer(func(w, r):
  w.WriteHeader(304)
)
client = NewClient(server.URL, WithAPIKey("key"))
resp, err = client.GetOrg(context.Background(), "org-1", WithIfNoneMatch("\"v1\""))
assert resp == nil
assert errors.Is(err, ErrNotModified)
// Demonstrate nil-safety: accessing resp.Data would panic
// Callers must guard with: if errors.Is(err, ErrNotModified) { ... }

// The SDK does not escape path parameters
// Callers are responsible for URL-safe IDs
client = NewClient("http://localhost:19999", WithAPIKey("key"))  // no server
err = client.AddOrgMember(context.Background(), "org-1", "user/with/slashes")
// Either transport error or malformed path — no *APIError
if err != nil:
  var apiErr *APIError
  assert errors.As(err, &apiErr) == false
